import type { BffResponse } from '@linm-soft/common-components';

/** Extract user-facing message from axios / unwrap errors (form-api-error-handling). */
export function resolveApiErrorMessage(err: unknown, fallback: string): string {
  if (err && typeof err === 'object' && 'response' in err) {
    const data = (err as { response?: { data?: BffResponse<unknown> } }).response?.data;
    if (data && data.success === false) {
      return data.error?.toastMessage || data.message || fallback;
    }
  }
  if (err instanceof Error && err.message.trim()) {
    return err.message;
  }
  return fallback;
}
